const selectedStatus = {{ statusTabs.value }};

// --- Helpers ---
function formatDate(dateStr) {
  if (!dateStr) return null;
  const d = new Date(dateStr);
  if (isNaN(d)) return null;
  const mm = String(d.getMonth() + 1).padStart(2, "0");
  const dd = String(d.getDate()).padStart(2, "0");
  const yyyy = d.getFullYear();
  return `${mm}-${dd}-${yyyy}`;
}

function parseDate(d) {
  if (!d) return null;
  const dt = new Date(d);
  return isNaN(dt) ? null : dt;
}

// --- Filter by selected tab ---
const filteredData = selectedStatus
  ? data.filter(r => {
      const raw = (r.current_status || "").toLowerCase().trim();
      const normalized = raw.replace(/^\d+\s*-\s*/, "").trim();
      const tab = selectedStatus.toLowerCase().trim();

      return (
        raw === tab ||
        normalized === tab ||
        raw.includes(tab) ||
        normalized.includes(tab)
      );
    })
  : data;

// --- Compute stats ---
const today = new Date();
today.setHours(0, 0, 0, 0);

const totalPackages = filteredData.length;
const totalWeldInches = filteredData.reduce(
  (sum, r) => sum + (r.total_weld_inches || 0),
  0
);
const totalFabHours = filteredData.reduce(
  (sum, r) => sum + (r.estimated_fab_hours || 0),
  0
);
const pastDue = filteredData.filter(r => {
  const date = parseDate(r.date_needed);
  return date && date < today;
}).length;

// --- Find next future package ---
const futurePackages = filteredData
  .filter(r => {
    const date = parseDate(r.date_needed);
    return date && date >= today;
  })
  .sort((a, b) => new Date(a.date_needed) - new Date(b.date_needed));

const nextDue = futurePackages.length > 0 ? futurePackages[0] : null;

// --- Find most recent past-due package ---
const pastPackages = filteredData
  .filter(r => {
    const date = parseDate(r.date_needed);
    return date && date < today;
  })
  .sort((a, b) => new Date(b.date_needed) - new Date(a.date_needed));

const lastPastDue = pastPackages.length > 0 ? pastPackages[0] : null;

// --- Return object for statistics ---
return {
  totalPackages,
  totalWeldInches,
  totalFabHours,
  pastDue,
  nextDue: nextDue
    ? { ...nextDue, formatted_date_needed: formatDate(nextDue.date_needed) }
    : null,
  lastPastDue: lastPastDue
    ? { ...lastPastDue, formatted_date_needed: formatDate(lastPastDue.date_needed) }
